mapper.select:
SELECT a.*, r.original_filename AS resumeName, j.title AS jobTitle, j.department AS jobDepartment, u.real_name AS candidateName, u.phone AS phone FROM application a LEFT JOIN resume r ON a.resume_id = r.id LEFT JOIN job_post j ON a.job_id = j.id LEFT JOIN sys_user u ON a.candidate_id = u.id
a.deleted = 0
AND (r.original_filename LIKE CONCAT('%', #{keyword}, '%') OR j.title LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}
AND a.job_id = #{jobId}
AND a.tags LIKE CONCAT('%', #{tag}, '%')
AND a.candidate_id = #{candidateId}
ORDER BY a.apply_time DESC
